import json
from pathlib import Path
from typing import Optional


def load_manifest(cache_dir: Path) -> list[dict]:
    """Load the org-roam export manifest."""
    manifest_path = cache_dir / "manifest.json"
    if not manifest_path.exists():
        raise FileNotFoundError(f"Manifest not found: {manifest_path}")
    with open(manifest_path) as f:
        return json.load(f)


def filter_public_nodes(nodes: list[dict]) -> list[dict]:
    """Return only nodes tagged 'public'."""
    return [
        node for node in nodes
        if "public" in node.get("tags", [])
    ]


if __name__ == "__main__":
    cache = Path("~/.cache/org-roam-export").expanduser()
    manifest = load_manifest(cache)
    public = filter_public_nodes(manifest)
    print(f"Public nodes: {len(public)}")

use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::path::PathBuf;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct IndexEntry {
    pub id: String,
    pub title: String,
    pub slug: String,
    pub aliases: Vec<String>,
    pub tags: Vec<String>,
    pub backlinks: Vec<BacklinkEntry>,
    pub last_modified: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BacklinkEntry {
    pub id: String,
    pub title: String,
    pub slug: String,
}

pub fn slugify(title: &str) -> String {
    title
        .to_lowercase()
        .chars()
        .map(|c| if c.is_alphanumeric() { c } else { '-' })
        .collect::<String>()
        .split('-')
        .filter(|s| !s.is_empty())
        .collect::<Vec<_>>()
        .join("-")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_slugify_basic() {
        assert_eq!(slugify("Hello World"), "hello-world");
        assert_eq!(slugify("Foo  Bar---Baz"), "foo-bar-baz");
    }
}

// Pagefind integration helper
async function initSearch() {
  const pagefind = await import('/pagefind/pagefind.js');
  await pagefind.init();

  const input = document.getElementById('search-input');
  const results = document.getElementById('search-results');

  input.addEventListener('input', async (e) => {
    const query = e.target.value.trim();
    if (!query) {
      results.innerHTML = '';
      return;
    }

    const search = await pagefind.search(query);
    const items = await Promise.all(
      search.results.slice(0, 10).map(r => r.data())
    );

    results.innerHTML = items
      .map(item => `<li><a href="${item.url}">${item.meta.title}</a></li>`)
      .join('');
  });
}

document.addEventListener('DOMContentLoaded', initSearch);

